#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=155;
int n,v[N],a[N],ans[N],ans2,dp[N][N][3];
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdou);
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		cin>>v[i];
	}
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
	}
    const int INF = -1e9;
    for(int i=0;i<=n;i++)
        for(int j=0;j<=n;j++)
            for(int k=0;k<3;k++)
                dp[i][j][k] = INF;

	for(int i=1;i<=n;i++)
	{
		dp[i][i][0]=v[1];
		dp[i][i][1]=dp[i][i][2]=0;
		dp[i][i-1][0]=0;
	}
	for(int len=2;len<=n;len++)
	{
		for(int l=1,r=len;r<=n;l++,r++)
		{
			for(int k=l;k<=r;k++)
			{
				int tmp=2*a[k]+1-a[l]-a[r];
				if(1<=tmp&&tmp<=n) dp[l][r][0]=max(dp[l][r][0],dp[l][k][1]+dp[k][r][2]+v[tmp]);
				if(k==r) break;
				if(a[k]==a[r]-1) dp[l][r][1]=max(dp[l][r][1],dp[l][k][1]+dp[k+1][r-1][0]);
				if(a[k]==a[r]+1) dp[l][r][2]=max(dp[l][r][2],dp[l][k][2]+dp[k+1][r-1][0]);
				dp[l][r][0]=max(dp[l][r][0],dp[l][k][0]+dp[k+1][r][0]);
			}
//			cout<<l<<" "<<r<<" "<<dp[l][r][0]<<" "<<dp[l][r][1]<<" "<<dp[l][r][2]<<"\n";
		}
	}
	for(int i=1;i<=n;i++)
	{
		ans[i]=ans[i-1];
		for(int j=1;j<=i;j++)
		{
			ans[i]=max(ans[i],ans[j-1]+dp[j][i][0]);
		}
		ans2=max(ans2,ans[i]);
	}
	cout<<ans2;
	return 0;
}
